// Compare current holder list with stored list to find NEW holders
// Static data persists between executions in n8n

const responseData = $input.first().json;

// Helius returns token accounts array
let tokenAccounts = [];
if (Array.isArray(responseData)) {
  tokenAccounts = responseData;
} else if (responseData.result) {
  tokenAccounts = responseData.result;
} else if (responseData.tokenAccounts) {
  tokenAccounts = responseData.tokenAccounts;
}

// Build current holder map: { walletAddress -> balance }
const currentHolders = {};
for (const acct of tokenAccounts) {
  const owner = acct.owner || acct.ownerAddress || acct.wallet || '';
  const rawAmount = parseFloat(acct.amount || acct.tokenAmount?.amount || 0);
  const decimals = acct.decimals || acct.tokenAmount?.decimals || 6;
  const balance = rawAmount / Math.pow(10, decimals);
  if (owner && balance > 0) {
    currentHolders[owner] = balance;
  }
}

// Retrieve previously stored holder list from Static Data
let staticData = $getWorkflowStaticData('global');
if (!staticData.knownHolders) {
  staticData.knownHolders = {};
}

const knownHolders = staticData.knownHolders;
const newHolders = [];

// Find wallets in currentHolders not in knownHolders
for (const [wallet, balance] of Object.entries(currentHolders)) {
  if (!knownHolders[wallet]) {
    newHolders.push({
      wallet,
      balance,
      shortAddr: wallet.slice(0, 4) + '...' + wallet.slice(-4)
    });
  }
}

// Update stored holder list
Object.assign(staticData.knownHolders, currentHolders);

const totalHolders = Object.keys(currentHolders).length;
const checkTimestamp = new Date().toISOString();

if (newHolders.length === 0) {
  return [{ json: { newHolders: [], totalHolders, checkTimestamp, hasNewHolders: false } }];
}

// Return one item per new holder
return newHolders.map(h => ({
  json: {
    ...h,
    totalHolders,
    checkTimestamp,
    hasNewHolders: true,
    allNewHolders: newHolders
  }
}));

// Format welcome message for each new holder
const d = $input.first().json;
const balanceFormatted = new Intl.NumberFormat('en-US').format(Math.round(d.balance));
const solscanUrl = `https://solscan.io/account/${d.wallet}`;

return [{
  json: {
    ...d,
    telegramMessage: `👋 NEW YAKK HOLDER!\n\n🏠 Wallet: \`${d.shortAddr}\`\n💰 Balance: ${balanceFormatted} $YST\n🎉 Welcome to the den!\n\n👥 Total Holders: ${d.totalHolders}\n🔍 [View Wallet](${solscanUrl})\n\n$YST #YakkStudios #Solana`
  }
}];
